void solve(int CASE)
{
    int n, m, q; cin >> n >> m >> q;
    var g = vector<vector<pii>>(n + 1);
    fa(i, 1, m) {
        int u, v, w; cin >> u >> v >> w;
        g[u].pb({ v,w });
    }
    var dp = Vec2<ll>(n + 1, 30);
    fa(i, 1, n)dp[i][0] = 1;
    fa(j, 1, 30)fa(now, 1, n)
        for (const var& [to, w] : g[now]) {
            dp[now][j] = max(dp[now][j], min((ll)1e9 + 1, dp[to][j - 1] * w));
        }
    while (q--) {
        int p, x; cin >> p >> x;
        fa(j, 1, 30) {
            if (dp[p][j] > x) {
                cout << j << endl;
                break;
            }
        }
    }
    return;
}
